import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';

function ProposalForm() {
  const { projectId } = useParams();
  const [project, setProject] = useState(null);
  const [form, setForm] = useState({ cover_letter: '', bid_amount: '', estimated_days: '' });
  const navigate = useNavigate();

  useEffect(() => {
    fetchProject();
  }, [projectId]);

  const fetchProject = async () => {
    try {
      const token = localStorage.getItem('access');
      const response = await axios.get(`http://127.0.0.1:8000/api/projects/${projectId}/`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setProject(response.data);
    } catch (error) {
      console.error('Error:', error);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const token = localStorage.getItem('access');
      await axios.post('http://127.0.0.1:8000/api/proposals/create/', {
        project: projectId, ...form
      }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      alert('Proposal submitted!');
      navigate('/projects');
    } catch (error) {
      alert('Failed to submit');
    }
  };

  if (!project) return <div>Loading...</div>;

  return (
    <div className="proposal-form">
      <h2>Submit Proposal for: {project.title}</h2>
      <form onSubmit={handleSubmit}>
        <textarea name="cover_letter" placeholder="Cover Letter" onChange={(e) => setForm({ ...form, cover_letter: e.target.value })} required />
        <input type="number" name="bid_amount" placeholder="Bid Amount (₹)" onChange={(e) => setForm({ ...form, bid_amount: e.target.value })} required />
        <input type="number" name="estimated_days" placeholder="Estimated Days" onChange={(e) => setForm({ ...form, estimated_days: e.target.value })} required />
        <button type="submit">Submit</button>
      </form>
    </div>
  );
}

export default ProposalForm;
